def is_prime(number: int) -> bool:
    if number < 2:
        return False

    sieve = [True] * (number + 1)
    sieve[0] = False
    sieve[1] = False

    for i in range(2, int(number**0.5) + 1):
        if sieve[i]:
            for j in range(i * i, number + 1, i):
                sieve[j] = False

    return sieve[number]
